const trigger = $('When Executed by Another Workflow').item.json;
const company_id = trigger.company_id || null;
const contact_id = trigger.contact_id || null;
const conversation_id = trigger.conversation_id || null;
const buffered_user_message = trigger.buffered_user_message || '';
const agent_response = trigger.agent_response || '';
const allItems = $input.all();
let messages = [];
try {
  if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
    messages = allItems[0].json;
  } else {
    messages = allItems.map(i => i.json).filter(m => m && m.body);
  }
} catch(e) { messages = []; }
messages.sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));
const recent = messages.slice(-15);
const roleLabel = (msg) => {
  const r = (msg.sender_type || '').toLowerCase();
  if (r === 'bot') return 'IA';
  if (r === 'agent') return 'Agente Humano';
  if (r === 'system') return 'Sistema';
  return 'Contato';
};
const lines = recent.map(msg => {
  const t = msg.created_at
    ? new Date(msg.created_at).toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'})
    : '??:??';
  return '[' + t + '] ' + roleLabel(msg) + ': ' + (msg.body || '').substring(0, 400);
});
if (buffered_user_message) lines.push('[AGORA] Contato: ' + buffered_user_message);
if (agent_response) lines.push('[AGORA] IA: ' + agent_response);
const fullTranscript = lines.join('\n');
const schemaLines = [
  '{',
  '  "estagio": "prospecção|qualificação|proposta|negociação|fechamento|suporte",',
  '  "resumo": "2-3 frases sobre o estado atual",',
  '  "ultima_acao_ia": "o que a IA fez por último",',
  '  "ultima_acao_humano": null,',
  '  "resposta_pendente_do_contato": true,',
  '  "orcamento_ou_proposta_enviada": false,',
  '  "contato_pediu_para_retornar": false,',
  '  "decisor_terceiro_mencionado": false,',
  '  "nivel_engajamento": "alto|médio|baixo|desengajado",',
  '  "objecao_detectada": null,',
  '  "evento_principal": "awaiting_contact_reply|qualification_question_sent|appointment_question_sent|quote_sent_waiting_reply|third_party_decision|asked_to_return_later|price_objection|no_followup_needed"',
  '}'
];
const system_prompt = 'Você é um analista de conversas comerciais. Sintetize o histórico e identifique o estado atual da negociação.\n\nResponda APENAS com JSON neste formato:\n' + schemaLines.join('\n');
const llm_payload = {
  model: 'gpt-4.1-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system_prompt },
    { role: 'user', content: 'Histórico (' + recent.length + ' msgs):\n\n' + (fullTranscript || '(sem histórico)') }
  ]
};
return [{
  json: {
    company_id, contact_id, conversation_id,
    buffered_user_message, agent_response,
    llm_payload, messages_analyzed: recent.length
  }
}];

const raw = $input.first().json;
const prep = $('prepara_followup_decision1').first().json;

let decision = {};
try {
  const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content ? raw.choices[0].message.content : '{}';
  decision = JSON.parse(content);
} catch(e) {
  decision = { should_create_trigger: false, confidence: 0, reason: 'parse_error: ' + e.message };
}

const confidence = parseFloat(decision.confidence || 0);
const shouldCreate = decision.should_create_trigger === true && confidence >= 0.65;
const windowMinutes = parseInt(decision.expected_reply_window_minutes || 1440);
const expectedReplyUntil = new Date(Date.now() + windowMinutes * 60 * 1000).toISOString();

return [{
  json: {
    should_create_trigger: shouldCreate,
    trigger_type: decision.trigger_type || 'no_response_after_ai_question',
    detected_event: decision.detected_event || 'awaiting_contact_reply',
    expected_reply_window_minutes: windowMinutes,
    expected_reply_until: expectedReplyUntil,
    reason: decision.reason || '',
    recommended_action: decision.recommended_action || '',
    recommended_followup_message: decision.recommended_followup_message || '',
    confidence: confidence,
    metadata: decision.metadata || {},
    company_id: prep.company_id,
    contact_id: prep.contact_id,
    conversation_id: prep.conversation_id
  }
}];

// Prepara o payload da agent_operation usando os dados da decisão de followup.
// Extrai nome do contato a partir das mensagens já buscadas no histórico.
var decision = $('parse_followup_decision1').first().json;

var contact_name = '';
try {
  var allMessages = $('busca_historico_conversa1').all().map(function(i) { return i.json; });
  var contactMsg = allMessages.find(function(m) { return m.sender_type === 'contact' && m.sender_name; });
  contact_name = (contactMsg && contactMsg.sender_name ? contactMsg.sender_name : '').trim();
} catch(e) { contact_name = ''; }

var words = contact_name.split(/\s+/).filter(Boolean);
var contact_initials = words.length >= 2
  ? (words[0][0] + words[words.length - 1][0]).toUpperCase()
  : contact_name.slice(0, 2).toUpperCase() || 'C';

// Mapeia trigger_type → operation_type e label visual
var typeMap = {
  'no_response_after_ai_question':  'follow_up',
  'no_response_after_human_message': 'follow_up',
  'third_party_decision_followup':  'escalate',
  'asked_to_return_later':          'confirm',
  'qualification_abandoned':        'rescue',
  'post_quote_followup':            'confirm'
};
var labelMap = {
  'follow_up': 'FOLLOW-UP',
  'escalate':  'ESCALAR',
  'confirm':   'CONFIRMAR',
  'rescue':    'RESGATE'
};

var operation_type  = typeMap[decision.trigger_type]  || 'follow_up';
var operation_label = labelMap[operation_type]        || 'FOLLOW-UP';

// Contexto resumido (máx 200 chars) para exibição no card
var context = (decision.reason || decision.detected_event || 'Follow-up automático').slice(0, 200);

// Chave de idempotência: conversation_id + tipo + data (evita duplicatas no mesmo dia)
var isoDate = new Date().toISOString().split('T')[0];
var idempotency_key = decision.conversation_id + ':' + operation_type + ':' + isoDate;

return [{
  json: {
    company_id:       decision.company_id,
    contact_id:       decision.contact_id,
    conversation_id:  decision.conversation_id,
    contact_name:     contact_name,
    contact_initials: contact_initials,
    operation_type:   operation_type,
    operation_label:  operation_label,
    message:          decision.recommended_followup_message || '',
    context:          context,
    reason:           decision.reason || null,
    send_at:          decision.expected_reply_until,
    source:           'agent',
    channel:          'whatsapp',
    idempotency_key:  idempotency_key
  }
}];
